// ============================================================
// JSONKB v1 — TRADE TERMINALS
// Inputs (by node name):
// - Terminals – Detail
// - Get KB share file
// - Set KB folder defaults
// ============================================================

// ---------- pull inputs ----------
const dItems = $items("Terminals – Detail");
if (!dItems || dItems.length === 0) {
  throw new Error('JSONKB Terminals: Missing input from node "Terminals – Detail".');
}
const row = dItems[0].json;



// ---------- helpers ----------
function slugify(s) {
  return String(s || '')
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-|-$/g, '');
}

function asNum(x) {
  if (x === null || x === undefined || x === '') return null;
  const n = Number(x);
  return Number.isFinite(n) ? n : null;
}

function compactObj(obj) {
  if (!obj || typeof obj !== 'object') return obj;
  const out = Array.isArray(obj) ? [] : {};
  for (const [k, v] of Object.entries(obj)) {
    if (v === null || v === undefined) continue;

    if (typeof v === 'object' && !Array.isArray(v)) {
      const inner = compactObj(v);
      if (inner && Object.keys(inner).length) out[k] = inner;
      continue;
    }

    if (Array.isArray(v)) {
      if (v.length) out[k] = v;
      continue;
    }

    out[k] = v;
  }
  return out;
}

// deep-stable stringify (prevents hash flapping)
function stableStringify(value) {
  const seen = new WeakSet();
  function norm(v) {
    if (v === null || v === undefined) return v;

    if (typeof v === 'object') {
      if (seen.has(v)) return null;
      seen.add(v);

      if (Array.isArray(v)) return v.map(norm);

      const out = {};
      for (const k of Object.keys(v).sort()) out[k] = norm(v[k]);
      return out;
    }
    return v;
  }
  return JSON.stringify(norm(value));
}

// ---------- slug / name ----------
const name = row.name || 'Unknown Terminal';
const slug = slugify(row.slug || row.terminal_code || name);
if (!slug) throw new Error('JSONKB Terminals: slug is empty.');

// ---------- kb_links (share must exist; markdown runs first) ----------

const kb_links = {
  kb_page_path: `/kb/${slug}`,
  kb_browse_path: `/browse?category=terminal`,
};

// ---------- deterministic kb_text (spec template) ----------
const terminalType = row.terminal_type || 'terminal';
const locationName = row.location_name || 'Unknown location';
const systemName = row.system_name || 'Unknown system';

const kb_text =
  `${name} is a ${terminalType} terminal at ${locationName} in the ${systemName} system.`;

// ---------- derive small metadata ----------
function parseItemsListed(src) {
  // v0.5 detail SQL often emits items_with_price as json/jsonb/text
  if (Array.isArray(src)) return src;
  if (src && typeof src === 'object') {
    // could be object keyed; normalize to values
    return Array.isArray(Object.values(src)) ? Object.values(src) : [];
  }
  if (typeof src === 'string') {
    try {
      const j = JSON.parse(src);
      if (Array.isArray(j)) return j;
      if (j && typeof j === 'object') return Object.values(j);
    } catch (_) {
      return [];
    }
  }
  return [];
}

const items = parseItemsListed(row.items_with_price || row.items_listed || null);

// asset_types_served (compact, sorted, unique)
const assetTypes = Array.from(
  new Set(
    (items || [])
      .map(it => (it && typeof it === 'object') ? String(it.asset_type || '').trim().toLowerCase() : '')
      .filter(Boolean)
  )
).sort();

// has_live_prices: if there are any price rows at all
const hasLivePrices = (Array.isArray(items) && items.length > 0) ? true : null;

let entity_metadata = {
  terminal_type: terminalType || null,
  system_name: systemName || null,
  location_name: locationName || null,

  uex_terminal_code: row.terminal_code || row.code || null,

  asset_types_served: assetTypes.length ? assetTypes : null,
  has_live_prices: hasLivePrices,

  item_count: asNum(row.item_count) ?? (items.length ? items.length : null),
};

entity_metadata = compactObj(entity_metadata);

// ---------- rag_hints (LOCKED) ----------
const rag_hints = {
  sql_hints: [
    {
      id: "terminal.items_listed",
      description: "List assets at a terminal (commodities or items).",
      params: [{ name: "terminal_id", type: "uuid", required: true }],
      // exact locked template
      sql_template: "SELECT COALESCE((SELECT jsonb_agg(jsonb_build_object('item_name',di.item_name,'asset_type',di.asset_type,'buy_price',di.buy_price,'sell_price',di.sell_price) ORDER BY di.item_name) FROM (SELECT DISTINCT p.asset_type, COALESCE(p.asset_name,p.item_name,p.metadata->>'commodity_name',p.metadata->>'item_name',p.metadata->>'name') AS item_name, p.buy_price, p.sell_price FROM prices p WHERE p.terminal_id = :terminal_id) di),'[]'::jsonb) AS items_listed;"
    }
  ],
  notes: null
}; // :contentReference[oaicite:1]{index=1}

// ---------- provenance ----------
const provenance = {
  generated_at: new Date().toISOString(),
  kb_generator_workflow: 'JSONKB - Trade Terminals v1',
  game_version: row.game_version || null,
  is_live_only: true,
};

// ---------- hash (single hash includes rag_hints) ----------
function fnv1a32Hex(str) {
  let hash = 0x811c9dc5;
  for (let i = 0; i < str.length; i++) {
    hash ^= str.charCodeAt(i);
    hash = (hash + ((hash << 1) + (hash << 4) + (hash << 7) + (hash << 8) + (hash << 24))) >>> 0;
  }
  return hash.toString(16).padStart(8, '0');
}
function hash16(str) {
  const a = fnv1a32Hex(str);
  const b = fnv1a32Hex(str + '|v2');
  return a + b;
}

// ---------- JSONKB object ----------
const jsonkb = {
  kb_version: '1.0',

  entity_type: 'terminal',
  entity_id: row.id || null,
  entity_slug: slug,
  entity_name: name,

  source: 'uex',
  // If your terminals table has a UEX id/code, keep it; otherwise, null is acceptable.
  source_id: row.source_id || ((row.uex_terminal_id != null) ? `terminals:${row.uex_terminal_id}` : (row.source_id || null)),
  source_table: 'trade_terminals',

  kb_text,
  kb_links,
  entity_metadata,
  rag_hints,
  provenance,
};

const hashBasis = stableStringify({
  entity_type: jsonkb.entity_type,
  entity_id: jsonkb.entity_id,
  kb_text: jsonkb.kb_text,
  entity_metadata: jsonkb.entity_metadata,
  rag_hints: jsonkb.rag_hints,
});

jsonkb.provenance.content_hash = hash16(hashBasis);

// ---------- JSONKB file path ----------
const jsonkb_file_path = `/kb/terminal/${slug}`;

return [
  {
    json: {
      terminal_id: row.id,
      slug,
      name,
      jsonkb,
      jsonkb_file_path,
    },
  },
];

