const buildResult = $('Build JSONKB').item.json;
const existingRow = items[0].json;
const currentHash = buildResult.jsonkb?.provenance?.content_hash || null;
const existingHash = existingRow?.content_hash || null;
const should_write = !existingHash || existingHash !== currentHash;
return [{ json: { ...buildResult, should_write, existing_hash: existingHash } }];
